SELECT d.dt, d.product_name, d.brand_name, COUNT(DISTINCT d.order_id) AS total_orders, COUNT(DISTINCT CASE WHEN n.is_user_brand_first_order=1 THEN d.order_id END) AS brand_new_orders, ROUND(COUNT(DISTINCT CASE WHEN n.is_user_brand_first_order=1 THEN d.order_id END)*100.0/COUNT(DISTINCT d.order_id),2) AS brand_new_rate FROM mart_lingshou.aggr_ord_order_detail_gtv_dd d LEFT JOIN mart_lingshou.aggr_usr_user_poi_gtv_first_order_info_base_dd n ON d.order_id = n.order_id AND n.dt >= '20260301' WHERE d.dt >= '20260301' AND d.operate_owner_type_v2_name = '非食专卖业务组' AND d.second_owner_name LIKE '%旗舰%' AND d.is_arrange = 1 AND d.product_name IS NOT NULL AND d.product_name != '' GROUP BY d.dt, d.product_name, d.brand_name HAVING COUNT(DISTINCT d.order_id) >= 10 ORDER BY d.dt DESC, total_orders DESC
